import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"轩辕后裔","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/6.一次性改造/轩辕后裔.md","filePath":"4.资源分区/2.改造与功法/改造/6.一次性改造/轩辕后裔.md"}'),d={name:"4.资源分区/2.改造与功法/改造/6.一次性改造/轩辕后裔.md"};function p(l,a,_,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"轩辕后裔",tabindex:"-1"},[s("轩辕后裔 "),e("a",{class:"header-anchor",href:"#轩辕后裔","aria-label":'Permalink to "轩辕后裔"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌037")])])],-1),o('<h1 id="轩辕后裔-1" tabindex="-1">轩辕后裔 <a class="header-anchor" href="#轩辕后裔-1" aria-label="Permalink to &quot;轩辕后裔&quot;">​</a></h1><p>轩辕后裔 <br> B+2400<br> 轩辕一脉早已衰落，但在某个世界，它又再次出现，在那这种体质被称为灵体，体内蕴含五行。轩辕传人天生拥有金发与重瞳，传说中他们能变化成古老的神龙作战。</p><p>【灵体】：身上每一颗细胞都是储存能量的器官，身体变得极度纯净没有任何杂质，你开启一个特殊的能量池【元灵】，关键属性是【决心+耐力】，这些能量储存在细胞内部，只有在使用时才会迸发。<br> 【元灵】恢复方式：当人物进行一次长休息，恢复所有元灵能量。当人物进行一次短休息，恢复耐力与决心属性平均值的元灵。每日恢复的能量上限不能超过能量池大小的三倍。<br> ST选开：正常来讲这种体质的人修炼天赋也是大幅提升，正常低魔环境修炼十年不到应该就可以达到一等高手境界，在更高能级修真世界就是天才，而且体液也蕴含能量，可以补魔，也很容易被人抓走抽血炼丹。<br> 该体质的人仇恨值更高，也可能招致不必要的麻烦，但是天资聪慧，在研读一些由ST认可的功法或典籍时获得额外2点附加成功。</p><p>地龙转生：消耗10点元灵，以一个整轮动作进行一次冲锋攻击，这次冲锋攻击不会导致你的基础防御降低，金色的光芒会从身上爆发，金光刺破云层，宛若天神降临，自身躯体笼罩在金色光球中，催生一种类似能量强化状态，这种情况下，你的生理属性检定上获得3点表现加值。你的肉搏或者施法攻击都将获得6点增强加值，体表的金芒闪烁宛若覆盖一层金甲，为自身提高7点天生防御，并且获得基于天生防御的【防能量】和2点全伤害吸收，以上效果持续一场景。</p><p>黄龙化：你可以自由动作引发血脉中的能力，你即刻化为神龙状态，通体鳞甲金黄，眼中的黄金瞳永久燃烧，头上长出弯曲狰狞的龙角，周身滚动之间，龙影在云层中翻涌，你获得了高空飞行的能力，机动性为完美…所化为黄龙，是代表五行的五灵之长，能调动大地戊土之力，你的攻击方式表现外观有所改变，比如施法可能是喷吐龙息，肉搏是在云层中穿梭厮杀……你在龙化后第一回合增加6点天生防御，在第二轮时，失去之前获得的天生防御，从而获得6点攻击增强加值，随后你可以每轮都进行一次转化,若转化，则需与上一轮结果不同。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
